ga3W(){return"Erfahre die wahren Kosten Deiner Mobilit\xe4t"},
ga3a(){return"W\xe4hle\xa0ein Verkehrsmittel aus und gib Start und Ziel Deines Weges in M\xfcnchen ein, um die wahren Kosten zu berechnen."},
gFa(){return"Vollkosten"},
