ga34(){return"Despite careful content control, we assume no liability for the content of external links. The operators of the linked pages are solely responsible for their content. Articles marked by name in the discussion areas reflect the author's opinion. The authors are solely responsible for the content of their contributions."},
gNP(){return"Privacy Policy"},
gOR(){return"General Information"},
ga57(){return"We take the protection of your personal data very seriously and treat your personal information confidentially and in accordance with legal data protection regulations as well as this privacy policy. This app does not require registration and does not store any personal data."},
ga5X(){return"Responsible Person"},
ga5a(){return"The entity responsible for data processing in accordance with the General Data Protection Regulation (GDPR) is:\n\nMCube\nFreddie-Mercury-Stra\xdfe 5\n80797 Munich\nPhone: +49 89 289-01\nE-Mail: sasim@mcube-cluster.com"},
ga_W(){return"Collection and Processing of Personal Data"},
ga54(){return"No personal data is stored or processed in the SASIM app. The use of the app does not require registration, and no user data that allows identification is stored."},
ga5h(){return"Processing of User Data"},
ga59(){return"The app only processes start and destination addresses entered by the user for routing purposes. These addresses are stored anonymously with a timestamp in log files, without any personal reference. This data is only used to provide the requested service and is not stored permanently."},
